const healthOut = ($('Health: Run research-health').item.json.stdout || '').toString();
const statsOut = ($('Health: Run research-stats').item.json.stdout || '').toString();
const healthExit = $('Health: Run research-health').item.json.exitCode || 0;
const statsExit = $('Health: Run research-stats').item.json.exitCode || 0;
const hasRed = healthOut.toLowerCase().includes('red') || healthOut.toLowerCase().includes('critical') || healthOut.toLowerCase().includes('fail') || healthOut.toLowerCase().includes('pipeline_failed') || healthOut.toLowerCase().includes('error') || healthExit !== 0 || statsExit !== 0;
return [{ json: { hasRed, healthOutput: healthOut.substring(0,1200), statsOutput: statsOut.substring(0,800), timestamp: new Date().toISOString(), healthExitCode: healthExit, statsExitCode: statsExit } }];

const d = $('Health: Parse Output').item.json;
const content = `**RIS Health Alert**

Health exit: ${d.healthExitCode} | Stats exit: ${d.statsExitCode}

**Health Output:**
\`\`\`
${d.healthOutput}
\`\`\`

**Stats:**
\`\`\`
${d.statsOutput}
\`\`\``;
return [{ json: { content } }];

const stdout = ($json.stdout || '').toString();
